private static PixelBuffer[] ProcessMultiImpl(PixelBuffer?[] inputs, IReadOnlyDictionary<string, object> parameters, PixelGraphContext context)
{
    var waveform = GetChoice(parameters, "waveform", "sine");
    var frequency = GetFloat(parameters, "frequency", 1f);
    var amplitude = GetFloat(parameters, "amplitude", 0.5f);
    var offset = GetFloat(parameters, "offset", 0f);
    var frame = GetFloat(parameters, "frame", 0f);
    var lineColor = GetColor(parameters, "color", Colors.Cyan);
    var thickness = GetFloat(parameters, "thickness", 1f);

    var size = context.TileSize;
    var image = new PixelBuffer(size, size);
    var mask = new PixelBuffer(size, size);

    var invSize = 1f / size;
    var colR = lineColor.R / 255f;
    var colG = lineColor.G / 255f;
    var colB = lineColor.B / 255f;

    image.ParallelForEachPixel((x, y) =>
    {
        var u = (x + 0.5f) * invSize; // Phase position 0-1
        var v = (y + 0.5f) * invSize; // Amplitude position 0-1

        // Effective phase: frequency * horizontal position + frame + offset
        var phase = frequency * u + frame + offset;
        var waveValue = ComputeWaveform(waveform, phase);

        // Apply amplitude and center in [0, 1] range
        var centered = (waveValue - 0.5f) * amplitude * 2f + 0.5f;
        centered = Math.Clamp(centered, 0f, 1f);

        // Draw waveform as a bright line on dark background
        // The line has a core (1 pixel) and a soft glow
        var dy = MathF.Abs(v - centered);

        // Core line intensity, scaled by thickness
        var core = MathF.Max(0f, 1f - dy * size * 4f / thickness);
        // Glow falloff, scaled by thickness
        var glow = MathF.Max(0f, 1f - dy * size * 1.2f / thickness);
        glow = glow * glow * 0.6f;

        // Grid lines (subtle but more visible)
        var gridX = MathF.Abs((u * 4f) % 1f - 0.5f) * 2f;
        var gridY = MathF.Abs((v * 4f) % 1f - 0.5f) * 2f;
        var grid = MathF.Max(gridX, gridY);
        var gridLine = grid > 0.97f ? 0f : (1f - grid * 20f) * 0.10f;

        // Center line (zero-crossing reference at v=0.5)
        var centerLine = MathF.Abs(v - 0.5f) * size < 1.5f ? 0.18f : 0f;

        // Compose using selected color
        var r = core * colR + glow * colR + gridLine + centerLine;
        var g = core * colG + glow * colG + gridLine + centerLine;
        var b = core * colB + glow * colB + gridLine + centerLine;

        // Current frame indicator (vertical line) — orange-highlight to distinguish from waveform color
        var frameLine = MathF.Abs(u - frame) * size < 1.5f ? 0.6f : 0f;
        r += frameLine;
        g += frameLine * 0.3f;
        b += frameLine * 0.1f;

        image.SetPixel(x, y,
            Math.Clamp(r, 0f, 1f),
            Math.Clamp(g, 0f, 1f),
            Math.Clamp(b, 0f, 1f),
            1f);

        // Mask: waveform value as grayscale
        mask.SetPixel(x, y,
            Math.Clamp(centered, 0f, 1f),
            Math.Clamp(centered, 0f, 1f),
            Math.Clamp(centered, 0f, 1f),
            1f);
    });

    return [image, mask];
}

/// <summary>
/// Computes the raw waveform value at a given phase, normalized to [0, 1].
/// </summary>
private static float ComputeWaveform(string waveform, float phase)
{
    // Wrap phase to [0, 1)
    var t = phase - MathF.Floor(phase);
    if (t < 0f) t += 1f;

    return waveform switch
    {
        "sawtooth" => t,
        "triangle" => 1f - MathF.Abs(t * 2f - 1f),
        "square" => t < 0.5f ? 1f : 0f,
        _ => MathF.Sin(t * MathF.PI * 2f) * 0.5f + 0.5f  // sine
    };
    }
}
